//                     ...incomes.map((income) => {
//                         const {amount} = income
//                         return amount
//                     })
//                 ],
//                 backgroundColor: 'green',
//                 tension: .2
//             },
//             {
//                 label: 'Expenses',
//                 data: [
//                     ...expenses.map((expense) => {
//                         const {amount} = expense
//                         return amount
//                     })
//                 ],
//                 backgroundColor: 'red',
//                 tension: .2
//             }
//         ]
//     }


//     return (
//         <ChartStyled >
//             <Line data={data} />
//         </ChartStyled>
//     )
// }
function Chart() {
    const { incomes, expenses } = useGlobalContext();

    // Format income and expense dates separately
    const incomeLabels = incomes.map((inc) => dateFormat(inc.date));
    const expenseLabels = expenses.map((exp) => dateFormat(exp.date));

    // Prepare data for incomes
    const incomeData = incomeLabels.map((date) => {
        const incomeEntry = incomes.find((inc) => dateFormat(inc.date) === date);
        return incomeEntry ? incomeEntry.amount : 0; // Use 0 if there's no income for that date
    });

    // Prepare data for expenses
    const expenseData = expenseLabels.map((date) => {
        const expenseEntry = expenses.find((exp) => dateFormat(exp.date) === date);
        return expenseEntry ? expenseEntry.amount : 0; // Use 0 if there's no expense for that date
    });

    // Combine unique labels for the x-axis
    const combinedLabels = [...new Set([...incomeLabels, ...expenseLabels])].sort();

    const data = {
        labels: combinedLabels,
        datasets: [
            {
                label: 'Income',
                data: combinedLabels.map((date) => {
                    const incomeEntry = incomes.find((inc) => dateFormat(inc.date) === date);
                    return incomeEntry ? incomeEntry.amount : 0; // Return amount or 0 if not found
                }),
                backgroundColor: 'green',
                tension: 0.2,
            },
            {
                label: 'Expenses',
                data: combinedLabels.map((date) => {
                    const expenseEntry = expenses.find((exp) => dateFormat(exp.date) === date);
                    return expenseEntry ? expenseEntry.amount : 0; // Return amount or 0 if not found
                }),
                backgroundColor: 'red',
                tension: 0.2,
            }
        ]
    };

    return (
        <ChartStyled>
            <Line data={data} />
        </ChartStyled>
    );
}


const ChartStyled = styled.div`
    background: #FCF6F9;
    border: 2px solid #FFFFFF;
    box-shadow: 0px 1px 15px rgba(0, 0, 0, 0.06);
    padding: 1rem;
    border-radius: 20px;
    height: 100%;
`;

export default Chart
